// frontend/src/App.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [weatherData, setWeatherData] = useState({
    temp_max: 25,
    temp_min: 18,
    temp_avg: 21.5,
    wind_speed: 15,
    humidity: 60,
    city: 'Tunis'
  });

  const [prediction, setPrediction] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [riskInfo, setRiskInfo] = useState([]);
  const [governorates, setGovernorates] = useState([]);

  // Tunisian governorates with coordinates (for visual appeal)
  const tunisianCities = [
    'Tunis', 'Ariana', 'Ben Arous', 'Manouba', 'Nabeul', 'Zaghouan',
    'Bizerte', 'Beja', 'Jendouba', 'Kef', 'Siliana', 'Sousse',
    'Monastir', 'Mahdia', 'Sfax', 'Kairouan', 'Kasserine', 'Sidi Bouzid',
    'Gabes', 'Medenine', 'Tataouine', 'Gafsa', 'Tozeur', 'Kebili'
  ];

  // Fetch risk info on component mount
  useEffect(() => {
    fetchRiskInfo();
    fetchGovernorates();
  }, []);

  const fetchRiskInfo = async () => {
    try {
      const response = await axios.get('http://localhost:8000/risk-info');
      setRiskInfo(response.data.levels);
    } catch (err) {
      console.error('Error fetching risk info:', err);
    }
  };

  const fetchGovernorates = async () => {
    try {
      const response = await axios.get('http://localhost:8000/governorates');
      setGovernorates(response.data.governorates);
    } catch (err) {
      console.error('Error fetching governorates:', err);
      // Fallback to local list if API fails
      setGovernorates(tunisianCities);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setWeatherData(prev => {
      const newData = { ...prev, [name]: value };
      
      // Auto-calculate average if both min and max are present
      if (name === 'temp_max' || name === 'temp_min') {
        const max = parseFloat(name === 'temp_max' ? value : prev.temp_max);
        const min = parseFloat(name === 'temp_min' ? value : prev.temp_min);
        if (!isNaN(max) && !isNaN(min)) {
          newData.temp_avg = ((max + min) / 2).toFixed(1);
        }
      }
      
      return newData;
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    
    try {
      // Convert string values to numbers
      const payload = {
        temp_max: parseFloat(weatherData.temp_max),
        temp_min: parseFloat(weatherData.temp_min),
        temp_avg: parseFloat(weatherData.temp_avg),
        wind_speed: parseFloat(weatherData.wind_speed),
        humidity: parseFloat(weatherData.humidity),
        city: weatherData.city
      };
      
      const response = await axios.post('http://localhost:8000/predict', payload);
      setPrediction(response.data);
    } catch (err) {
      setError(err.response?.data?.detail || 'Error making prediction');
      console.error('Prediction error:', err);
    } finally {
      setLoading(false);
    }
  };

  const getRiskColor = (riskLevel) => {
    const colors = {
      'GREEN': '#4CAF50',
      'YELLOW': '#FFC107',
      'ORANGE': '#FF9800',
      'RED': '#F44336',
      'PURPLE': '#9C27B0'
    };
    return colors[riskLevel] || '#999';
  };

  const getRiskEmoji = (riskLevel) => {
    const emojis = {
      'GREEN': '✅',
      'YELLOW': '⚠️',
      'ORANGE': '⚡',
      'RED': '🔴',
      'PURPLE': '🟣'
    };
    return emojis[riskLevel] || '❓';
  };

  return (
    <div className="App">
      <header className="app-header">
        <h1>🌤️ WeatherGuardTN</h1>
        <p>Tunisia Weather Danger & Vigilance Predictor</p>
      </header>

      <div className="main-container">
        {/* Risk Legend */}
        <div className="risk-legend">
          <h3>Risk Levels</h3>
          <div className="legend-items">
            {riskInfo.map(risk => (
              <div key={risk.code} className="legend-item">
                <span className="legend-color" style={{ backgroundColor: risk.color === '🟢' ? '#4CAF50' : 
                                                                             risk.color === '🟡' ? '#FFC107' :
                                                                             risk.color === '🟠' ? '#FF9800' :
                                                                             risk.color === '🔴' ? '#F44336' : '#9C27B0' }}></span>
                <span className="legend-name">{risk.name}</span>
                <span className="legend-desc">{risk.description}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Input Form */}
        <div className="input-section">
          <h2>Enter Weather Data</h2>
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>City:</label>
              <select 
                name="city" 
                value={weatherData.city} 
                onChange={handleInputChange}
                required
              >
                {governorates.map(city => (
                  <option key={city} value={city}>{city}</option>
                ))}
              </select>
            </div>

            <div className="form-row">
              <div className="form-group">
                <label>Max Temp (°C):</label>
                <input
                  type="number"
                  name="temp_max"
                  value={weatherData.temp_max}
                  onChange={handleInputChange}
                  step="0.1"
                  min="-10"
                  max="50"
                  required
                />
              </div>

              <div className="form-group">
                <label>Min Temp (°C):</label>
                <input
                  type="number"
                  name="temp_min"
                  value={weatherData.temp_min}
                  onChange={handleInputChange}
                  step="0.1"
                  min="-10"
                  max="50"
                  required
                />
              </div>
            </div>

            <div className="form-group">
              <label>Avg Temp (°C):</label>
              <input
                type="number"
                name="temp_avg"
                value={weatherData.temp_avg}
                onChange={handleInputChange}
                step="0.1"
                required
              />
            </div>

            <div className="form-row">
              <div className="form-group">
                <label>Wind Speed (km/h):</label>
                <input
                  type="number"
                  name="wind_speed"
                  value={weatherData.wind_speed}
                  onChange={handleInputChange}
                  step="0.1"
                  min="0"
                  max="200"
                  required
                />
              </div>

              <div className="form-group">
                <label>Humidity (%):</label>
                <input
                  type="number"
                  name="humidity"
                  value={weatherData.humidity}
                  onChange={handleInputChange}
                  step="1"
                  min="0"
                  max="100"
                  required
                />
              </div>
            </div>

            <button type="submit" disabled={loading} className="predict-btn">
              {loading ? 'Predicting...' : 'Predict Risk'}
            </button>
          </form>
        </div>

        {/* Prediction Result */}
        {prediction && (
          <div className="result-section">
            <h2>Prediction Result</h2>
            <div 
              className="result-card" 
              style={{ backgroundColor: getRiskColor(prediction.risk_level) }}
            >
              <div className="result-header">
                <span className="result-emoji">{getRiskEmoji(prediction.risk_level)}</span>
                <span className="result-risk">{prediction.risk_level}</span>
              </div>
              
              <div className="result-details">
                <p><strong>City:</strong> {prediction.city}</p>
                <p><strong>Confidence:</strong> {prediction.confidence}%</p>
                
                <div className="weather-details">
                  <h4>Weather Conditions:</h4>
                  <p>🌡️ Max: {prediction.weather.temp_max}°C</p>
                  <p>🌡️ Min: {prediction.weather.temp_min}°C</p>
                  <p>🌡️ Avg: {prediction.weather.temp_avg}°C</p>
                  <p>💨 Wind: {prediction.weather.wind_speed} km/h</p>
                  <p>💧 Humidity: {prediction.weather.humidity}%</p>
                </div>

                <div className="probabilities">
                  <h4>Probability Distribution:</h4>
                  {Object.entries(prediction.probabilities).map(([risk, prob]) => (
                    <div key={risk} className="probability-bar">
                      <span>{risk}</span>
                      <div className="bar-container">
                        <div 
                          className="bar" 
                          style={{ 
                            width: `${prob}%`,
                            backgroundColor: getRiskColor(risk)
                          }}
                        ></div>
                        <span className="bar-value">{prob.toFixed(1)}%</span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {error && (
          <div className="error-message">
            ❌ Error: {error}
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
